-- SQL Schema for StayEasy Hostel Management System\n\nCREATE TABLE admins (\n    admin_id INT PRIMARY KEY AUTO_INCREMENT,\n    username VARCHAR(50) NOT NULL,\n    password VARCHAR(255) NOT NULL,\n    email VARCHAR(100) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE students (\n    student_id INT PRIMARY KEY AUTO_INCREMENT,\n    student_name VARCHAR(100) NOT NULL,\n    email VARCHAR(100) NOT NULL,\n    phone VARCHAR(15),\n    enrollment_date DATE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE rooms (\n    room_id INT PRIMARY KEY AUTO_INCREMENT,\n    room_number VARCHAR(10) UNIQUE NOT NULL,\n    room_type VARCHAR(50) NOT NULL,\n    capacity INT NOT NULL,\n    price DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE room_images (\n    image_id INT PRIMARY KEY AUTO_INCREMENT,\n    room_id INT NOT NULL,\n    image_url VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (room_id) REFERENCES rooms(room_id) ON DELETE CASCADE\n);\n\nCREATE TABLE fees (\n    fee_id INT PRIMARY KEY AUTO_INCREMENT,\n    student_id INT NOT NULL,\n    amount DECIMAL(10, 2) NOT NULL,\n    fee_date DATE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (student_id) REFERENCES students(student_id) ON DELETE CASCADE\n);\n\nCREATE TABLE complaints (\n    complaint_id INT PRIMARY KEY AUTO_INCREMENT,\n    student_id INT NOT NULL,\n    complaint_text TEXT NOT NULL,\n    complaint_date DATE NOT NULL,\n    status VARCHAR(20) DEFAULT 'Pending',\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (student_id) REFERENCES students(student_id) ON DELETE CASCADE\n);\n\nCREATE TABLE room_requests (\n    request_id INT PRIMARY KEY AUTO_INCREMENT,\n    student_id INT NOT NULL,\n    room_id INT NOT NULL,\n    request_date DATE NOT NULL,\n    status VARCHAR(20) DEFAULT 'Pending',\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (student_id) REFERENCES students(student_id) ON DELETE CASCADE,\n    FOREIGN KEY (room_id) REFERENCES rooms(room_id) ON DELETE CASCADE\n);\n\n-- Sample Data\n\nINSERT INTO admins (username, password, email) VALUES\n('admin1', 'password1', 'admin1@example.com'),\n('admin2', 'password2', 'admin2@example.com');\n\nINSERT INTO students (student_name, email, phone, enrollment_date) VALUES\n('John Doe', 'johndoe@example.com', '1234567890', '2026-01-15'),\n('Jane Smith', 'janesmith@example.com', '0987654321', '2026-02-20');\n\nINSERT INTO rooms (room_number, room_type, capacity, price) VALUES\n('101', 'Single', 1, 500),\n('102', 'Double', 2, 800);\n\nINSERT INTO room_images (room_id, image_url) VALUES\n(1, 'http://example.com/images/room101.jpg'),\n(2, 'http://example.com/images/room102.jpg');\n\nINSERT INTO fees (student_id, amount, fee_date) VALUES\n(1, 1500.00, '2026-03-01'),\n(2, 1800.00, '2026-03-02');\n\nINSERT INTO complaints (student_id, complaint_text, complaint_date) VALUES\n(1, 'The room is not clean.', '2026-03-10'),\n(2, 'There is no hot water.', '2026-03-11');\n\nINSERT INTO room_requests (student_id, room_id, request_date) VALUES\n(1, 2, '2026-03-12'),\n(2, 1, '2026-03-13');\n